import ast

def safe_eval(expr):
    try:
        return ast.literal_eval(expr)
    except ValueError:
        raise ValueError("Failed to evaluate expression: " + expr)
    except SyntaxError:
        raise ValueError("Invalid syntax in expression: " + expr)

